         설  명  : 시험기본수정
     */
	UPDATE TB_LMS_EXAM_BSC SET
		  MDFR_ID   = #{mdfrId}
		, MOD_DTTM = FN_DTTM()

		, SBJCT_ID = #{sbjctId}


		, LCTR_WKNO_SCHDL_ID = #{lctrWknoSchdlId}


		, EXAM_GRP_ID = #{examGrpId}


		, EXAM_TYCD = #{examTycd}


		, EXAM_GBNCD = #{examGbncd}


		, EXAM_TTL = #{examTtl}


		, EXAM_CTS = #{examCts}


		, TKEXAM_MTHD_CD = #{tkexamMthdCd}


		, QSTN_DSPLY_GBNCD = #{qstnDsplyGbncd}


		, EXAMPPR_OYN = #{exampprOyn}


		, AVG_MRK_OYN = #{avgMrkOyn}


		, MRK_OPEN_SDTTM = #{mrkOpenSdttm}


		, PUSH_NOTIYN = #{pushNotiyn}


		, SEC_CERT_CD = #{secCertCd}


		, IMDT_ANSW_SHT_INQYN = #{imdtAnswShtInqyn}


		, MAX_TKEXAM_CNT = #{maxTkexamCnt}


		, USEYN = #{useyn}


		, DELYN = #{delyn}


		, REGYN = #{regyn}


		, QSTNS_DLGTNYN = #{qstnsDlgtnyn}


		, MRK_OYN = #{mrkOyn}


		, DVCLAS_REGYN = #{dvclasRegyn}


		, EXAM_QSTNS_CMPTNYN = #{examQstnsCmptnyn}


		, QSTN_RNDMYN = #{qstnRndmyn}


		, QSTN_VWITM_RNDMYN = #{qstnVwitmRndmyn}


		, QSTN_CNDDT_USEYN = #{qstnCnddtUseyn}


		, MRK_RFLTYN = #{mrkRfltyn}


		, MRK_RFLTRT = #{mrkRfltrt}


		, EXAMTM_ALLOC_GBNCD = #{examtmAllocGbncd}


		, EXAMTM_EXPSR_TYCD = #{examtmExpsrTycd}


		, LRN_GRP_SUBASMT_STNGYN = #{lrnGrpSubasmtStngyn}

	WHERE EXAM_BSC_ID = #{examBscId}

	/*
         SQL ID : ExamMapper.examDtlModify
         설  명  : 시험상세수정
     */
	UPDATE TB_LMS_EXAM_DTL SET
		  MDFR_ID   = #{mdfrId}
		, MOD_DTTM = FN_DTTM()

