mapper.select:
/* SQL ID : ExamDAO.profAuthrtSbjctQuizList 설 명 : 교수권한과목퀴즈목록조회 */ SELECT ROW_NUMBER() OVER(ORDER BY EXAM_BSC.EXAM_BSC_ID DESC) AS LINE_NO , EXAM_BSC.EXAM_BSC_ID , EXAM_BSC.EXAM_TTL , SBJCT.SBJCT_ID , SBJCT.SBJCTNM , SBJCT.DVCLAS_NO , (SELECT CDNM FROM TB_LMS_CMMN_CD WHERE UP_CD = 'EXAM_GBNCD' AND CD = EXAM_BSC.EXAM_GBNCD) AS EXAM_GBNNM , COUNT(1) OVER() AS TOTAL_CNT FROM TB_LMS_SBJCT_ADM SBJCT_ADM JOIN TB_LMS_EXAM_BSC EXAM_BSC ON SBJCT_ADM.SBJCT_ID = EXAM_BSC.SBJCT_ID AND EXAM_BSC.DELYN = 'N' AND EXAM_BSC.USEYN = 'Y' JOIN TB_LMS_SBJCT SBJCT ON SBJCT.SBJCT_ID = EXAM_BSC.SBJCT_ID LEFT JOIN TB_LMS_SMSTR_CHRT SMSTR_CHRT ON (SBJCT.SMSTR_CHRT_ID = SMSTR_CHRT.SMSTR_CHRT_ID AND SBJCT.SBJCT_REF_TYCD = 'CHRT') WHERE SBJCT_ADM.USER_ID = #{userId} AND EXAM_BSC.EXAM_GBNCD IN ('QUIZ', 'QUIZ_TEAM') AND EXAM_BSC.EXAM_TYCD = 'QUIZ' AND SBJCT_ADM.SBJCT_ADM_TYCD = 'PROF'
AND SBJCT.SMSTR_CHRT_ID = #{smstrChrtId}
AND SBJCT.SBJCT_ID = #{sbjctId}
AND LOWER(EXAM_BSC.EXAM_TTL) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
ORDER BY EXAM_BSC.EXAM_BSC_ID

/* SQL ID : ExamDAO.quizLrnGrpSubAsmtList 설 명 : 퀴즈학습그룹부과제목록조회 */ SELECT TEAM.TEAM_ID , TEAM.TEAMNM , NVL((SELECT USR.USERNM FROM TB_LMS_USER USR JOIN TB_LMS_TEAM_MBR TEAM_MBR ON USR.USER_ID = TEAM_MBR.USER_ID WHERE TEAM_MBR.LDRYN = 'Y' AND TEAM_MBR.TEAM_ID = TEAM.TEAM_ID), '-') AS leaderNm , (SELECT COUNT(tlts.USER_ID) FROM TB_LMS_TEAM_MBR tlts WHERE tlts.TEAM_ID = TEAM.TEAM_ID) AS teamMbrCnt , EXAM_DTL.EXAM_TTL , EXAM_DTL.EXAM_CTS FROM TB_LMS_TEAM TEAM LEFT JOIN TB_LMS_EXAM_TRGTR EXAM_TRGTR ON TEAM.TEAM_ID = EXAM_TRGTR.TEAM_ID AND EXAM_TRGTR.EXAM_DTL_ID IN (SELECT EXAM_DTL_ID FROM TB_LMS_EXAM_BSC WHERE EXAM_BSC_ID = #{examBscId}) LEFT JOIN TB_LMS_EXAM_DTL EXAM_DTL ON EXAM_TRGTR.EXAM_DTL_ID = EXAM_DTL.EXAM_DTL_ID AND EXAM_DTL.DELYN = 'N' AND EXAM_DTL.USEYN = 'Y' AND EXAM_DTL.EXAM_BSC_ID = #{examBscId} WHERE TEAM.LRN_GRP_ID = #{lrnGrpId}
AND EXAM_DTL.EXAM_BSC_ID = #{examBscId}
ORDER BY TEAM.TEAM_ID ASC

