         	, REEXAM_PSBL_EDTTM = #{item.reexamPsblEdttm}
         	, REEXAM_MRK_RFLTRT = #{item.reexamMrkRfltrt}
          WHERE EXAM_DTL_ID = #{item.examDtlId}

