/*
    SQL ID : ExamDAO.updateMrkOyn
    설명 : 성적 공개여부 수정
*/
UPDATE
    TB_LMS_EXAM_BSC
SET
    MRK_OYN     =   #{mrkOyn}
WHERE
    EXAM_BSC_ID = #{examBscId}

/*
    SQL ID : ExamDAO.examMrkRfltrtListModify
    설  명 : 시험 성적 반영비율 수정
*/

    UPDATE
        TB_LMS_EXAM_BSC
    SET
        MDFR_ID         = #{item.mdfrId}
        , MOD_DTTM      = FN_DTTM()
        , MRK_RFLTRT    = #{item.mrkRfltrt}
    WHERE
        EXAM_BSC_ID = #{item.examBscId}

/*
    SQL ID : ExamDAO.updateExamBscInfo
    설명 : 시험 기본정보 수정
*/
UPDATE
    TB_LMS_EXAM_BSC
SET
    EXAM_GBNCD              =   #{examGbncd}
    , TKEXAM_MTHD_CD        =   #{tkexamMthdCd}
    , EXAM_TTL              =   #{examTtl}
    , MRK_RFLTYN            =   #{mrkRfltyn}
    , MRK_OYN               =   #{mrkOyn}
    , EXAMPPR_OYN           =   #{exampprOyn}
    , BYTEAM_SUBREXAM_USEYN =   #{byteamSubrexamUseyn}
    , MDFR_ID               =   #{mdfrId}
    , MOD_DTTM              =   FN_DTTM()
WHERE
    EXAM_BSC_ID = #{examBscId}

/*
    SQL ID : ExamDAO.updateExamDtlInfo
    설명 : 시험 상세정보 수정
*/
UPDATE
    TB_LMS_EXAM_DTL
SET
    EXAM_MNTS           =   #{examMnts}
    , EXAM_PSBL_SDTTM   =   #{examPsblSdttm}
    , EXAM_PSBL_EDTTM   =   #{examPsblEdttm}
    , EXAM_TTL          =   #{examTtl}
    , EXAM_CTS          =   #{examCts}
    , MDFR_ID           =   #{mdfrId}
    , MOD_DTTM          =   FN_DTTM()
WHERE
    EXAM_BSC_ID = #{examBscId}
